import React, { useRef, useState } from 'react';
import { Animated, Platform, Pressable, StyleSheet, Text, View, useWindowDimensions } from 'react-native';
import { COLORS, RADIUS } from '../constants/theme';
import { NAV_LINKS, PROFILE } from '../constants/data';
interface Props {
  scrollY: Animated.Value;
  onNavPress?: (section: string) => void;
}
export default function Navbar({ scrollY, onNavPress }: Props) {
  const { width } = useWindowDimensions();
  const isWide = width >= 768;
  const [hoveredLink, setHoveredLink] = useState<string | null>(null);
  const bgOpacity = scrollY.interpolate({
    inputRange: [0, 80],
    outputRange: [0, 1],
    extrapolate: 'clamp',
  });
  const webStyle =
    Platform.OS === 'web'
      ? ({ backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)', position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100 } as any)
      : {};
  return (
    <View style={[styles.wrapper, webStyle]}>
      <Animated.View style={[StyleSheet.absoluteFillObject, styles.navBgAnim, { opacity: bgOpacity }]} />
      <View style={styles.inner}>
        {/* Logo */}
        <Pressable onPress={() => onNavPress?.('hero')}>
          <View style={styles.logoBox}>
            <Text style={styles.logoText}>{PROFILE.initials}</Text>
          </View>
        </Pressable>
        {isWide && (
          <View style={styles.links}>
            {NAV_LINKS.map((link) => (
              <Pressable
                key={link.section}
                onPress={() => onNavPress?.(link.section)}
                onHoverIn={() => setHoveredLink(link.section)}
                onHoverOut={() => setHoveredLink(null)}
              >
                <Text style={[styles.link, hoveredLink === link.section && styles.linkHover]}>
                  {link.label}
                </Text>
              </Pressable>
            ))}
          </View>
        )}
        <Pressable
          style={({ pressed, hovered }: any) => [
            styles.hireMeBtn,
            (pressed || hovered) && styles.hireMeBtnHover,
          ]}
          onPress={() => onNavPress?.('contact')}
        >
          <Text style={styles.hireMeText}>Hire Me</Text>
        </Pressable>
      </View>
    </View>
  );
}
const styles = StyleSheet.create({
