/**
 * Web animation helpers for react-native-web.
 *
 * Uses `animationName` to reference @keyframes injected by injectGlobalStyles().
 * This is the reliable approach — `animationKeyframes` with transform arrays
 * does NOT generate valid CSS inside react-native-web's @keyframes builder,
 * causing all animations to freeze.
 *
 * The `animationName` property shows a dev-only validation warning in RNW but
 * works correctly in all environments (warning is suppressed in production).
 */

/** Build a base web animation style object. */
function wa(
  name: string,
  duration: string,
  timing = 'ease',
  delay = '0s',
  iteration = 'infinite',
  fill = 'both',
  direction?: string,
): any {
  return {
    animationName: name,
    animationDuration: duration,
    animationTimingFunction: timing,
    animationDelay: delay,
    animationIterationCount: iteration,
    animationFillMode: fill,
    ...(direction ? { animationDirection: direction } : {}),
  };
}

